head.script:
scwin.processFlag = "";
scwin.mhnoFlg = "";
scwin.E_MSG_ERR_001 = "전표번호가  (@) 존재 합니다. 수정 삭제 할 수 없습니다.";
scwin.vUserId = "";
scwin.hid_kcomcd = "DBEX";
scwin.hid_sellVatNo = "";
scwin.hid_intendDt = "";
scwin.hid_bilgPicNo = "";
scwin.hid_bilgPicNm = "";
scwin.hid_commNm = "DBEX";
scwin.txt_countRow = "";
scwin.txa_certiPatternCd = "";
scwin.txa_vatYn = "";
scwin.dtl_sellVatNo = "";
scwin.dtl_offsetVatNo = "";
scwin.nowDt = "";
scwin.paramKcomcd = "DBEX";
scwin.paramSeaair = "S";
scwin.paramIogb = "O";
scwin.paramMblno = "";
scwin.paramBlno = "";
scwin.paramMhno = "";
scwin.paramPrtnGrpNo = "";
scwin.paramBilgClntNo = "";

scwin.onpageload = async function() {
    scwin.vUserId = $c.ses.getEmpNo();
    scwin.nowDt = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    let params = $c.data.getParameter();
    if (params != null) {
        scwin.paramKcomcd = params.kcomcd || "DBEX";
        scwin.paramSeaair = params.seaair || "S";
        scwin.paramIogb = params.iogb || "O";
        scwin.paramMblno = params.mblno || "";
        scwin.paramBlno = params.blno || "";
        scwin.paramMhno = params.mhno || "";
        scwin.paramPrtnGrpNo = params.prtnGrpNo || "";
        scwin.paramBilgClntNo = params.bilgClntNo || "";
    }
    scwin.hid_kcomcd = scwin.paramKcomcd;

    scwin.f_initSetTab();
    scwin.f_Set("INIT");
    scwin.f_DefaultValue();
    scwin.processFlag = "INIT";
    cnd_ed_mblno.setFocus();

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);
    $c.gus.cfDisableObjects([ica_tempBilgIntendDt]);
};

scwin.f_initSetTab = async function() {
    scwin.f_selectTabMenu(0);
};

scwin.f_DefaultValue = async function() {
    acb_seaair.setValue(scwin.paramSeaair);
    acb_iogb.setValue(scwin.paramIogb);
    cnd_ed_mblno.setValue(scwin.paramMblno);
    cnd_ed_blno.setValue(scwin.paramBlno);
    cnd_ed_prtnGrpNo.setValue(scwin.paramPrtnGrpNo);
    cnd_ed_bilgClntNo.setValue(scwin.paramBilgClntNo);

    if (cnd_ed_mblno.getValue() != "") {
        scwin.f_MhnoLoading("M", cnd_ed_mblno.getValue());
    }

    if (cnd_ed_blno.getValue() != "") {
        scwin.f_MhnoLoading("H", cnd_ed_blno.getValue());
    }

    // TODO: cnd_lc_mhno.setValue(scwin.paramMhno);

    rd_enggb.setValue("1");
    rd_prebilgYn.setValue("0");
    chb_pre.setValue("0");
};

scwin.f_Set = async function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            if (scwin.processFlag == "RETRIEVE") {
                $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
                $c.gus.cfEnableBtnOnly([btn_Update, btn_Delete, btn_Print]);
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Update, btn_Save, btn_Delete]);
                $c.gus.cfEnableBtnOnly([btn_Create]);
            }
            break;
        case "CANCEL":
            scwin.f_Set("RETRIEVE");
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            if (ds_invoiceCommon.getCellData(ds_invoiceCommon.getRowPosition(), "crcCd") == "KRW") {
                chb_billgb.setDisabled(true);
            } else {
                chb_billgb.setDisabled(false);
            }
            break;
        case "UPDATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            chb_billgb.setDisabled(true);
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = async function() {
    // TODO: enable popup image objects for bilgDt, bilgPicNo
};

scwin.f_DisablePopUpObj = async function() {
    // TODO: disable popup image objects for bilgDt, bilgPicNo
};

scwin.f_selectTabMenu = async function(idx) {
    switch (idx) {
        case 0:
            break;
        case 1:
            break;
        case 2:
            break;
    }
    $c.gus.cfViewTab(idx);
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_mblno.getValue().trim() == "" && cnd_ed_blno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master or House B/L"]);
        cnd_ed_mblno.setFocus();
        return;
    }

    ds_invoiceList.removeAll();
    ds_invoiceCommon.removeAll();
    ds_invoiceFreight.removeAll();

    dma_search.set("kcomcd", scwin.hid_kcomcd);
    dma_search.set("seaair", acb_seaair.getValue());
    dma_search.set("iogb", acb_iogb.getValue());
    dma_search.set("mblno", cnd_ed_mblno.getValue());
    dma_search.set("blno", cnd_ed_blno.getValue());
    dma_search.set("mhno", acb_taxnClsCd.getValue());
    dma_search.set("prtnGrpNo", cnd_ed_prtnGrpNo.getValue());
    dma_search.set("bilgClntNo", cnd_ed_bilgClntNo.getValue());
    dma_search.set("bilgClntNm", cnd_txt_bilgClntNm.getValue());
    dma_search.set("dept", cnd_ed_dept.getValue());
    dma_search.set("deptnm", cnd_txt_deptnm.getValue());
    dma_search.set("certiNo", "");

    await $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    chb_billgb.setValue("");
    if (ds_invoiceList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        $c.gus.cf_ShowTotalRows(totalRows, ds_invoiceList.getRowCount());
    }
};

scwin.sbm_retrieve_submiterror = async function(e) {
    $c.gus.cfShowError(e);
    chb_billgb.setValue("");
};

scwin.f_RetrievePrint = async function() {
    if (acb_printOp.getValue() == "5") {
        scwin.f_RetrieveCertiPrint();
    } else {
        scwin.f_RetrieveTaxPrint();
    }
};

scwin.f_SendEmail = async function() {
    let row = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(row, "seaair") == "S") {
        let odiParam = new ODIParam("ac_101_01_01_sea");
        odiParam.add("KCOMCD", ds_invoiceList.getCellData(row, "kcomcd"));
        odiParam.add("PRTN_GRP_NO", ds_invoiceList.getCellData(row, "prtnGrpNo"));
        odiParam.add("SEAAIR", "S");
        odiParam.add("IOGB", ds_invoiceList.getCellData(row, "iogb"));
        odiParam.add("BILG_CLNT_NO", ds_invoiceList.getCellData(row, "bilgClntNo"));
        odiParam.add("USER_ID", ds_invoiceList.getCellData(row, "modId"));
        odiParam.add("TYPE", acb_printOp.getValue());
        odiParam.add("RMK", rd_billgb.getValue());
        odiParam.add("REMARK", txa_summary.getValue());
        odiParam.add("ENG", rd_enggb.getValue());

        if (ed_bilgPicNo.getValue() != "") {
            odiParam.add("PIC", "1");
        } else {
            odiParam.add("PIC", "2");
        }

        let formParam = new FormParam();
        let viewerParam = new ViewerParam();
        viewerParam.add("viewer.mode", "export");
        viewerParam.add("viewer.useprogressbar", "false");
        viewerParam.add("viewer.exportcommand", "true");
        viewerParam.add("export.mode", "silent");
        viewerParam.add("export.path", "C:\\");
        viewerParam.add("export.filename", "certi");
        viewerParam.add("export.format", "pdf");
        viewerParam.add("export.confirmsave", "false");
        viewerParam.add("export.target", "email");

        $c.gus.cfOZExport("/il/acc/ac_101_01_01_sea.ozr", odiParam, viewerParam, formParam);
    } else {
        let odiParam = new ODIParam("ac_101_01_01_air");
        odiParam.add("KCOMCD", ds_invoiceList.getCellData(row, "kcomcd"));
        odiParam.add("PRTN_GRP_NO", ds_invoiceList.getCellData(row, "prtnGrpNo"));
        odiParam.add("SEAAIR", "A");
        odiParam.add("IOGB", ds_invoiceList.getCellData(row, "iogb"));
        odiParam.add("BILG_CLNT_NO", ds_invoiceList.getCellData(row, "bilgClntNo"));
        odiParam.add("USER_ID", ds_invoiceList.getCellData(row, "modId"));
        odiParam.add("TYPE", acb_printOp.getValue());
        odiParam.add("RMK", rd_billgb.getValue());
        odiParam.add("REMARK", txa_summary.getValue());
        odiParam.add("ENG", rd_enggb.getValue());

        if (ed_bilgPicNo.getValue() != "") {
            odiParam.add("PIC", "1");
        } else {
            odiParam.add("PIC", "2");
        }

        let formParam = new FormParam();
        let viewerParam = new ViewerParam();
        viewerParam.add("viewer.mode", "export");
        viewerParam.add("viewer.useprogressbar", "false");
        viewerParam.add("viewer.exportcommand", "true");
        viewerParam.add("export.mode", "silent");
        viewerParam.add("export.path", "C:\\");
        viewerParam.add("export.filename", "certi");
        viewerParam.add("export.format", "pdf");
        viewerParam.add("export.confirmsave", "false");
        viewerParam.add("export.target", "email");

        $c.gus.cfOZExport("/il/acc/ac_101_01_01_air.ozr", odiParam, viewerParam, formParam);
    }
    OZExecuteBatch();
};

scwin.f_RetrieveTaxPrint = async function() {
    let row = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(row, "sellVatNo") == "") {
        await $c.win.alert("세금계산서 / 전표를 먼저 생성 하세요");
        return;
    }
    scwin.hid_sellVatNo = ds_invoiceList.getCellData(row, "sellVatNo");
    dma_search.set("sellVatNo", ds_invoiceList.getCellData(row, "sellVatNo"));
    await $c.sbm.execute(sbm_retrieveTaxPrint);
};

scwin.sbm_retrieveTaxPrint_submitdone = async function(e) {
    scwin.f_TaxPrint();
};

scwin.sbm_retrieveTaxPrint_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_RetrieveCertiPrint = async function() {
    let row = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(row, "certiNo") == "") {
        await $c.win.alert("Invoice를 먼저 생성 하세요");
        return;
    }
    dma_search.set("certiNo", ds_invoiceList.getCellData(row, "certiNo"));
    await $c.sbm.execute(sbm_retrieveCertiPrint);
};

scwin.sbm_retrieveCertiPrint_submitdone = async function(e) {
    scwin.f_CertiPrint();
};

scwin.sbm_retrieveCertiPrint_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_RetrieveCommon = async function() {
    ds_invoiceCommon.removeAll();
    ds_invoiceFreight.removeAll();
    await $c.sbm.execute(sbm_retrieveCommon);
};

scwin.sbm_retrieveCommon_submitdone = async function(e) {
    if (ds_invoiceCommon.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
            if (ds_invoiceCommon.getCellData(i, "certiNo") == "") {
                ds_invoiceCommon.setCellData(i, "spplyAmt", 0);
                ds_invoiceCommon.setCellData(i, "spplyAmtFcrc", 0);
                ds_invoiceCommon.setCellData(i, "vatAmt", 0);
                ds_invoiceCommon.setCellData(i, "fcrcBilgAmt", 0);
                ds_invoiceCommon.setCellData(i, "bilgAmt", 0);
                ds_invoiceCommon.setCellData(i, "bilgAmtFcrc", 0);
            }
            if (ds_invoiceCommon.getCellData(i, "chk") == "F") {
                ds_invoiceCommon.setCellData(i, "chk", "T");
            }
            ds_invoiceCommon.setCellData(i, "spplyAmtOri",
                Number(ds_invoiceCommon.getCellData(i, "spplyAmt")) + Number(ds_invoiceCommon.getCellData(i, "vatAmt")));
        }
    }

    ica_bilgIntendDt.setValue(scwin.hid_intendDt);
    ed_bilgPicNo.setValue(scwin.hid_bilgPicNo);
    txt_bilgPicNm.setValue(scwin.hid_bilgPicNm);

    let listRow = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(listRow, "certiNo") == "" && ds_invoiceList.getCellData(listRow, "bilgClntNo") == "308556") {
        scwin.f_heinzRmk();
    }

    if (ds_invoiceFreight.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        scwin.hid_commNm = ds_invoiceFreight.getCellData(0, "commNm");
        for (let i = 0; i < ds_invoiceFreight.getRowCount(); i++) {
            if (ds_invoiceFreight.getCellData(i, "chk") == "F") {
                ds_invoiceFreight.setCellData(i, "chk", "T");
            }
        }
    }
};

scwin.sbm_retrieveCommon_submiterror = async function(e) {
    $c.gus.cfShowError(e);
    chb_billgb.setValue("");
};

scwin.f_Create = async function() {
    scwin.f_Set("CREATE");
    scwin.f_billgbSetting();
    ica_bilgIntendDt.setValue(scwin.nowDt);
    ica_bilgIntendDt.setFocus();
};

scwin.f_Update = async function() {
    scwin.f_Set("UPDATE");
    ica_bilgIntendDt.setFocus();
};

scwin.f_Undo = async function() {
    ds_invoiceList.undoRow(ds_invoiceList.getRowPosition());
    ds_invoiceCommon.undoRow(ds_invoiceCommon.getRowPosition());
    ds_invoiceFreight.removeAll();
    scwin.f_Set("CANCEL");
};

scwin.f_Save = async function() {
    let vCountRow = ds_invoiceList.getRowCount();

    for (let i = 0; i < vCountRow; i++) {
        let vCurRowStatus = ds_invoiceList.getRowStatus(i);
        if (vCurRowStatus == "U" || vCurRowStatus == "D") {
            if (ds_invoiceList.getCellData(i, "slipNo") != "") {
                await $c.gus.cfAlertMsg(scwin.E_MSG_ERR_001, [ds_invoiceList.getCellData(i, "slipNo")]);
                return;
            }
        }
    }

    if (ds_invoiceCommon.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_invoiceFreight.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_invoiceList.getUpdatedIndex().length == 0 && ds_invoiceCommon.getUpdatedIndex().length == 0 && ds_invoiceFreight.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Invoice"]);
        return false;
    }

    if ($c.gus.cfGetByteLength(txa_summary.getValue()) > 500) {
        await $c.gus.cfAlertMsg("Remark는 공백포함 영문500자, 한글250자 만 입력가능합니다.");
        txa_summary.setFocus();
        return;
    }

    if (ds_invoiceCommon.getRowCount() > 1) {
        for (let i = 1; i < ds_invoiceCommon.getRowCount(); i++) {
            if (ds_invoiceCommon.getCellData(0, "summary") != "") {
                ds_invoiceCommon.setCellData(i, "summary", ds_invoiceCommon.getCellData(0, "summary"));
            }
        }
    }

    let fcodecnt = 0;
    let fcodesum = 0;
    let fcode = "";
    let wfcode = 0;
    let tfcode = 0;

    for (let i = 0; i < ds_invoiceFreight.getRowCount(); i++) {
        if (ds_invoiceFreight.getCellData(i, "chk") == "T") {
            if (ds_invoiceFreight.getCellData(i, "fareEngCd") == "WFG" || ds_invoiceFreight.getCellData(i, "fareEngCd") == "TSG") {
                fcodesum += Number(ds_invoiceFreight.getCellData(i, "sellAmt"));
                if (ds_invoiceFreight.getCellData(i, "fareEngCd") == "WFG") { wfcode++; }
                if (ds_invoiceFreight.getCellData(i, "fareEngCd") == "TSG") { tfcode++; }
                fcodecnt++;
            }
        }
    }

    if (wfcode > 0 && tfcode > 0) { fcode = "WFG/TSG"; }
    else if (wfcode > 0) { fcode = "WFG"; }
    else if (tfcode > 0) { fcode = "TSG"; }

    if (fcodecnt > 0) {
        for (let i = 0; i < ds_invoiceFreight.getRowCount(); i++) {
            if (ds_invoiceFreight.getCellData(i, "chk") == "T" && Number(ds_invoiceFreight.getCellData(i, "vatAmt")) == 0) {
                ds_invoiceFreight.setCellData(i, "summary", fcode + " : " + fcodesum + "  " + ds_invoiceCommon.getCellData(0, "crcCd"));
            }
        }
    }

    if (scwin.f_chk_billgbSetting()) {
        let chkValid = await scwin.f_ReqFieldChk();
        if (chkValid) {
            let chk = await $c.gus.cfConfirmMsg(E_MSG_CM_CRM_001);
            if (chk) {
                await $c.sbm.execute(sbm_save);
                scwin.processFlag = "RETRIEVE";
                scwin.f_Set("RETRIEVE");
            }
        }
    }
};

scwin.f_PrtnGrpNo = async function() {
    let cf = ds_invoiceList.getRowCount();

    for (let i = 0; i < cf; i++) {
        if (ds_invoiceList.getCellData(i, "prtnGrpNo") != "") {
            ds_invoiceList.setCellData(i, "prtnGrpNo", ed_prtnGrpNo.getValue());
        }
    }

    let row = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(row, "slipNo") != "") {
        await $c.gus.cfAlertMsg(scwin.E_MSG_ERR_001, [ds_invoiceList.getCellData(row, "slipNo")]);
        return;
    }

    if (ds_invoiceCommon.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_invoiceFreight.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_invoiceList.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Invoice"]);
        return false;
    }

    let chk = await $c.gus.cfConfirmMsg(E_MSG_CM_CRM_001);
    if (chk) {
        await $c.sbm.execute(sbm_prtnGrpNo);
        scwin.processFlag = "RETRIEVE";
        scwin.f_Set("RETRIEVE");
    }
};

scwin.f_Delete = async function() {
    let row = ds_invoiceList.getRowPosition();
    if (ds_invoiceList.getCellData(row, "slipNo") != "") {
        await $c.gus.cfAlertMsg(scwin.E_MSG_ERR_001, [ds_invoiceList.getCellData(row, "slipNo")]);
        return;
    }

    let chk = await $c.gus.cfConfirmMsg(E_MSG_CM_CRM_004);
    if (chk) {
        let cf = ds_invoiceCommon.getRowCount();
        for (let i = cf - 1; i >= 0; i--) {
            if (ds_invoiceCommon.getCellData(i, "chk") == "T") {
                ds_invoiceCommon.removeRow(i);
            }
        }
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([oDetailInfo]);
    return chk;
};

scwin.f_SlipPopUp = async function() {
    let cf = ds_invoiceCommon.getRowCount();
    for (let i = 0; i < cf; i++) {
        if (ds_invoiceCommon.getCellData(i, "chk") == "T") {
            if (ds_invoiceCommon.getCellData(i, "prtnGrpNo") != "") {
                let listRow = ds_invoiceList.getRowPosition();
                let blno = ds_invoiceList.getCellData(listRow, "blno");
                let intendDt = ica_bilgIntendDt.getValue().trim();
                let kcomcd = ds_invoiceList.getCellData(listRow, "kcomcd");
                let prtnGrpNo = ds_invoiceList.getCellData(listRow, "prtnGrpNo");
                let seaair = ds_invoiceList.getCellData(listRow, "seaair");
                let iogb = ds_invoiceList.getCellData(listRow, "iogb");
                let bilgClntNo = ds_invoiceList.getCellData(listRow, "bilgClntNo");
                let userId = ds_invoiceList.getCellData(listRow, "modId");
                let type = acb_printOp.getValue();
                let rmk = rd_billgb.getValue();
                let remark = txa_summary.getValue();
                let summary = ds_invoiceFreight.getCellData(0, "summary");
                let eng = rd_enggb.getValue();
                let locPtnCls = "1";
                let pic = (ed_bilgPicNo.getValue() != "") ? 1 : 2;

                $c.gus.cfCopyDataSet(ds_invoiceCommon, ds_certiCommonDs, "copyHeader=yes");
                ds_certiCommonDs.setCellData(0, "receptClsCd", "02");

                let obj = {
                    blno: blno,
                    intendDt: intendDt,
                    kcomcd: kcomcd,
                    prtnGrpNo: prtnGrpNo,
                    seaair: seaair,
                    iogb: iogb,
                    bilgClntNo: bilgClntNo,
                    userId: userId,
                    type: type,
                    rmk: rmk,
                    remark: remark,
                    eng: eng,
                    locPtnCls: locPtnCls,
                    pic: pic,
                    summary: summary,
                    ds_certiCommonDs: ds_certiCommonDs,
                    commNm: scwin.hid_commNm
                };

