scwin.f_PopUp = async function(disGubun, chgGubun) {
    switch (disGubun) {
        case "bilgClntNo":
            udc_bilgClnt.ilCommonPopUp(scwin.callbackBilgClnt,
                cnd_ed_bilgClntNo.getValue().trim(),
                cnd_txt_bilgClntNm.getValue(),
                chgGubun, "5", "Customer", "140,300",
                null, null, "500", "500", null, null, null,
                "F", "Customer Search,Customer Code,Customer Name");
            break;
        case 2:
            if (ed_bilgClntNo.getValue().trim() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Customer"]);
                ed_bilgClntNo.setFocus();
                return;
            }
            udc_bilgPic.ilCommonPopUp(scwin.callbackBilgPic,
                ed_bilgPicNo.getValue().trim(),
                txt_bilgPicNm.getValue(),
                chgGubun, "4", "PIC", "100,350",
                null, ed_bilgClntNo.getValue().trim(), "500", "500", null, null, null,
                "T", null);
            break;
        case 3:
            udc_dept.ilCommonPopUp(scwin.callbackDept,
                cnd_ed_dept.getValue().trim(),
                cnd_txt_deptnm.getValue(),
                "T", "2", "Code, Name", "80,230",
                "3,4,5,6,7,8,9,10", null, null, null, null, null, null,
                "F", "Department,Code,Name", "F");
            break;
        default:
            break;
    }
};

