scwin.f_MhnoLoading = async function(mhgb, blno) {
    let strClntNo = blno;
    if (strClntNo.length > 0) {
        let param1 = strClntNo;
        let seaairVal = acb_seaair.getValue();
        let iogbVal = acb_iogb.getValue();
        let queryId = "";

        if (seaairVal == "A") {
            queryId = (mhgb == "M") ? "retriveAirMasterMhnoListCombo" : "retriveAirHouseMhnoListCombo";
        } else if (seaairVal == "S") {
            queryId = (mhgb == "M") ? "retriveSeaMasterMhnoListCombo" : "retriveSeaHouseMhnoListCombo";
        } else if (seaairVal == "T") {
            if (mhgb == "M") {
                await $c.win.alert("After House B/L No Input. Search Pls.");
                return;
            } else {
                queryId = "retriveTransMhnoListCombo";
            }
        }
        // TODO: ds_mhno combo loading via sbm_mhnoLoading with queryId, param1, iogbVal
        await $c.sbm.execute(sbm_mhnoLoading);
    }
};

scwin.sbm_mhnoLoading_submitdone = async function(e) {
    if (ds_mhno.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    } else {
        if (scwin.paramMblno != "" || scwin.paramBlno != "") {
            scwin.f_Retrieve();
        }
    }
};

scwin.sbm_mhnoLoading_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

