scwin.ds_invoiceList_onrowpositionchange = function(rowIndex, oldRow) {
    let row = rowIndex;
    if (row >= 0) {
        let vRowStatus = ds_invoiceList.getRowStatus(row);

        let kcomcd = ds_invoiceList.getCellData(row, "kcomcd");
        let seaair = ds_invoiceList.getCellData(row, "seaair");
        let iogb = ds_invoiceList.getCellData(row, "iogb");
        let mblno = ds_invoiceList.getCellData(row, "mblno");
        let blno = ds_invoiceList.getCellData(row, "blno");
        let mhno = ds_invoiceList.getCellData(row, "mhno");
        let certiNo = ds_invoiceList.getCellData(row, "certiNo");
        let prtnGrpNo = ds_invoiceList.getCellData(row, "prtnGrpNo");
        let bilgClntNo = ds_invoiceList.getCellData(row, "bilgClntNo");
        let bilgClntNm = ds_invoiceList.getCellData(row, "bilgClntNm");
        let slipNo = ds_invoiceList.getCellData(row, "slipNo");
        let odrNo = ds_invoiceList.getCellData(row, "odrNo");
        let intendDt = ds_invoiceList.getCellData(row, "confirmDt");
        let bilgPicNo = ds_invoiceList.getCellData(row, "bilgPicNo");
        let bilgPicNm = ds_invoiceList.getCellData(row, "bilgPicNm");

        dma_searchFreight.set("kcomcd", kcomcd);
        dma_searchFreight.set("seaair", seaair);
        dma_searchFreight.set("iogb", iogb);
        dma_searchFreight.set("mblno", mblno);
        dma_searchFreight.set("blno", blno);
        dma_searchFreight.set("mhno", mhno);
        dma_searchFreight.set("certiNo", certiNo);
        dma_searchFreight.set("prtnGrpNo", prtnGrpNo);
        dma_searchFreight.set("bilgClntNo", bilgClntNo);
        dma_searchFreight.set("bilgClntNm", bilgClntNm);
        dma_searchFreight.set("odrNo", odrNo);
        dma_searchFreight.set("slipNo", slipNo);

        scwin.hid_intendDt = intendDt;
        scwin.hid_bilgPicNo = bilgPicNo;
        scwin.hid_bilgPicNm = bilgPicNm;

        acb_taxnClsCd.setValue(ds_invoiceList.getCellData(row, "taxnClsCd"));
        if (ds_invoiceList.getCellData(row, "taxnClsCd") == "") {
            if (Number(ds_invoiceList.getCellData(row, "sumVatAmt")) == 0) {
                acb_taxnClsCd.setValue("02");
                $c.gus.cfDisableObjects([acb_taxnClsCd]);
            } else {
                acb_taxnClsCd.setValue("01");
                $c.gus.cfEnableObjects([acb_taxnClsCd]);
            }
        }

        if (vRowStatus == "R") {
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            if (prtnGrpNo.trim() == "") {
                $c.gus.cfEnableBtnOnly([btn_Create]);
                scwin.processFlag = "INIT";
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Create, btn_Save, btn_Update, btn_Delete, btn_Print, btn_Tax]);
                if (slipNo == "") {
                    $c.gus.cfEnableBtnOnly([btn_Update, btn_Delete, btn_Print]);
                    if (certiNo != "") {
                        $c.gus.cfEnableBtnOnly([btn_Tax]);
                    }
                    scwin.processFlag = "RETRIEVE";
                } else {
                    $c.gus.cfEnableBtnOnly([btn_Print, btn_Tax]);
                    scwin.processFlag = "RETRIEVE";
                }
            }
        } else if (vRowStatus == "C") {
            scwin.f_Set("CREATE");
        } else if (vRowStatus == "U") {
            scwin.f_Set("UPDATE");
        }
    } else {
        scwin.f_Set("INIT");
        scwin.processFlag = "INIT";
    }
};

scwin.ds_invoiceList_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;
    if (ds_invoiceList.getRowCount() > 0) {
        switch (colid) {
            case "confirmDt":
                let confirmDt = ds_invoiceList.getCellData(row, "confirmDt");
                for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                    ds_invoiceCommon.setCellData(i, "confirmDt", confirmDt);
                    ds_invoiceCommon.setCellData(i, "bilgIntendDt", confirmDt);
                }
                break;
            case "bilgPicNo":
                let bpNo = ed_bilgPicNo.getValue();
                let bpNm = txt_bilgPicNm.getValue();
                for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                    ds_invoiceCommon.setCellData(i, "bilgPicNo", bpNo);
                    ds_invoiceCommon.setCellData(i, "bilgPicNm", bpNm);
                }
                break;
            case "clntBilgDocNo":
                let clntBilgDocNo = ds_invoiceList.getCellData(row, "clntBilgDocNo");
                for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                    ds_invoiceCommon.setCellData(i, "clntBilgDocNo", clntBilgDocNo);
                }
                break;
            default:
                break;
        }
    }
};

scwin.ds_invoiceFreight_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;
    let vatCnt = 0;
    if (ds_invoiceFreight.getRowCount() > 0) {
        if (colid == "chk") {
            let refkey = ds_invoiceFreight.getCellData(row, "refkey");
            let spplyAmt = Number(ds_invoiceFreight.getCellData(row, "sellAmt"));
            let spplyAmtFcrc = Number(ds_invoiceFreight.getCellData(row, "sellAmtFcrc"));
            let vatAmt = Number(ds_invoiceFreight.getCellData(row, "vatAmt"));
            let fcrcBilgAmt = 0;

            if (ds_invoiceFreight.getCellData(row, "crcCd") == "KRW") {
                fcrcBilgAmt = 0;
            } else {
                fcrcBilgAmt = Number(ds_invoiceFreight.getCellData(row, "sellAmt"));
            }
            let bilgAmt = spplyAmt + vatAmt - fcrcBilgAmt;
            let bilgAmtFcrc = Number(ds_invoiceFreight.getCellData(row, "sellAmtFcrc"));

            for (let i = 0; i < ds_invoiceFreight.getRowCount(); i++) {
                if (ds_invoiceFreight.getCellData(i, "chk") == "T" && refkey == ds_invoiceFreight.getCellData(i, "refkey")) {
                    vatCnt = vatCnt + 1;
                }
            }

            for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                if (ds_invoiceFreight.getCellData(row, "chk") == "T" && refkey == ds_invoiceCommon.getCellData(i, "refkey")) {
                    ds_invoiceCommon.setCellData(i, "spplyAmt", Number(ds_invoiceCommon.getCellData(i, "spplyAmt")) + spplyAmt);
                    ds_invoiceCommon.setCellData(i, "spplyAmtFcrc", Number(ds_invoiceCommon.getCellData(i, "spplyAmtFcrc")) + spplyAmtFcrc);
                    ds_invoiceCommon.setCellData(i, "vatAmt", Number(ds_invoiceCommon.getCellData(i, "vatAmt")) + vatAmt);
                    ds_invoiceCommon.setCellData(i, "fcrcBilgAmt", Number(ds_invoiceCommon.getCellData(i, "fcrcBilgAmt")) + fcrcBilgAmt);
                    ds_invoiceCommon.setCellData(i, "bilgAmt", Number(ds_invoiceCommon.getCellData(i, "bilgAmt")) + bilgAmt);
                    ds_invoiceCommon.setCellData(i, "bilgAmtFcrc", Number(ds_invoiceCommon.getCellData(i, "bilgAmtFcrc")) + bilgAmtFcrc);
                } else if (ds_invoiceFreight.getCellData(row, "chk") == "F" && refkey == ds_invoiceCommon.getCellData(i, "refkey")) {
                    ds_invoiceCommon.setCellData(i, "spplyAmt", Number(ds_invoiceCommon.getCellData(i, "spplyAmt")) - spplyAmt);
                    ds_invoiceCommon.setCellData(i, "spplyAmtFcrc", Number(ds_invoiceCommon.getCellData(i, "spplyAmtFcrc")) - spplyAmtFcrc);
                    ds_invoiceCommon.setCellData(i, "vatAmt", Number(ds_invoiceCommon.getCellData(i, "vatAmt")) - vatAmt);
                    ds_invoiceCommon.setCellData(i, "fcrcBilgAmt", Number(ds_invoiceCommon.getCellData(i, "fcrcBilgAmt")) - fcrcBilgAmt);
                    ds_invoiceCommon.setCellData(i, "bilgAmt", Number(ds_invoiceCommon.getCellData(i, "bilgAmt")) - bilgAmt);
                    ds_invoiceCommon.setCellData(i, "bilgAmtFcrc", Number(ds_invoiceCommon.getCellData(i, "bilgAmtFcrc")) - bilgAmtFcrc);
                }
            }

            if (vatCnt < 1) {
                for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                    if (ds_invoiceCommon.getCellData(i, "chk") == "T" && refkey == ds_invoiceCommon.getCellData(i, "refkey")) {
                        ds_invoiceCommon.setCellData(i, "chk", "F");
                    }
                }
            } else {
                for (let i = 0; i < ds_invoiceCommon.getRowCount(); i++) {
                    if (ds_invoiceCommon.getCellData(i, "chk") == "F" && refkey == ds_invoiceCommon.getCellData(i, "refkey")) {
                        ds_invoiceCommon.setCellData(i, "chk", "T");
                    }
                }
            }
        }
    }
};

