            case "billgb":
                let listRow = ds_invoiceList.getRowPosition();
                if (ds_invoiceList.getCellData(listRow, "certiNo") == "") {
                    let billgbChecked = (chb_billgb.getValue() != "" && chb_billgb.getValue() != "0" && chb_billgb.getValue() != "F");
                    if (!billgbChecked && acb_printOp.getValue() != "6") {
                        scwin.f_RetrieveCommon();
                    } else if (billgbChecked) {
                        let cr = ds_invoiceFreight.getRowCount();
                        if (cr > 0) {
                            for (let i = 0; i < cr; i++) {
                                if (ds_invoiceFreight.getCellData(i, "chk") == "T") {
                                    if (ds_invoiceFreight.getCellData(i, "crcCd").trim() != "KRW") {
                                        ds_invoiceFreight.setCellData(i, "crcCd", "KRW");
                                        ds_invoiceFreight.setCellData(i, "exRate", 0);
                                        ds_invoiceFreight.setCellData(i, "sellAmtFcrc", 0);
                                        ds_invoiceFreight.setCellData(i, "spplyAmtFcrc", 0);
                                        ds_invoiceFreight.setCellData(i, "bilgInscrpAmtFcrc", 0);
                                    }
                                }
                            }
                        }
                        let rc = ds_invoiceCommon.getRowCount();
                        if (rc > 0) {
                            for (let i = 0; i < rc; i++) {
                                ds_invoiceCommon.setCellData(i, "crcCd", "KRW");
                                ds_invoiceCommon.setCellData(i, "spplyAmtFcrc", 0);
                                ds_invoiceCommon.setCellData(i, "fcrcBilgAmt", 0);
                                ds_invoiceCommon.setCellData(i, "bilgAmtFcrc", 0);
                                ds_invoiceCommon.setCellData(i, "bilgAmt",
                                    Number(ds_invoiceCommon.getCellData(i, "spplyAmt")) + Number(ds_invoiceCommon.getCellData(i, "vatAmt")) - Number(ds_invoiceCommon.getCellData(i, "fcrcBilgAmt")));
                                ds_invoiceCommon.setCellData(i, "crcCd", "KRW");
                            }
                        }
                    }
                }
                break;
            default:
                break;
        }
    }
};

