scwin.acb_taxnClsCd_onchange = function(e) {
    if (acb_taxnClsCd.getValue() == "03") {
        let rc = ds_invoiceCommon.getRowCount();
        if (rc > 0) {
            for (let i = 0; i < rc; i++) {
                if (ds_invoiceCommon.getCellData(i, "taxnClsCd") == "02") {
                    ds_invoiceCommon.setCellData(i, "taxnClsCd", acb_taxnClsCd.getValue());
                }
            }
        }
    }
};

scwin.cnd_ed_blno_onblur = function(e) {
    scwin.f_MhnoLoading("H", cnd_ed_blno.getValue().trim());
};

scwin.cnd_ed_mblno_onblur = function(e) {
    scwin.f_MhnoLoading("M", cnd_ed_mblno.getValue().trim());
};

scwin.cnd_ed_prtnGrpNo_onblur = function(e) {
    dma_search.set("prtnGrpNo", cnd_ed_prtnGrpNo.getValue().trim());
};

scwin.acb_printOp_onchange = function(e) {
    if (acb_printOp.getValue() == "5") {
        $c.gus.cfEnableBtnOnly([btn_Tax]);
    }
    if (acb_printOp.getValue() == "2") {
        $c.gus.cfEnableObjects([ica_tempBilgIntendDt]);
    } else {
        $c.gus.cfDisableObjects([ica_tempBilgIntendDt]);
        ica_tempBilgIntendDt.setValue("");
    }
    if (acb_printOp.getValue() == "6") {
        for (let i = 0; i < ds_invoiceFreight.getRowCount(); i++) {
            if (ds_invoiceFreight.getCellData(i, "crcCd") == "KRW") {
                ds_invoiceFreight.setCellData(i, "chk", "F");
            } else {
                ds_invoiceFreight.setCellData(i, "chk", "T");
            }
        }
    }
};

